sparql:
SELECT ?player ?birthYear WHERE {
  ?player wdt:P569 ?birthYear .
  FILTER(STR(?birthYear) = '1950')
}

SELECT ?game ?year WHERE {
  ?game wdt:P1344 wd:Q1363275 .
  ?game wdt:P571 ?year .
  FILTER((?year = '1977' || ?year = '1978' || ?year = '2008' || ?year = '2009'))
}

SELECT ?birthDate WHERE {
  wd:Q862468 wdt:P569 ?birthDate
}

SELECT ?game WHERE {
  ?series ?p ?game .
}
LIMIT 10

SELECT ?series WHERE {
  wd:Q213959 wdt:P118 ?series
}

SELECT ?club(STR(?wins) AS ?wins_count) WHERE {
  VALUES ?club {
    wd:Q297104 wd:Q2521385 wd:Q251090 wd:Q1084121 wd:Q2738554
  }
  ?club wdt:P1355 ?wins .
}
ORDER BY ?wins_count

SELECT ?competition ?attendance WHERE {
  wd:Q213959 wdt:P118 ?competition .
  ?competition wdt:P1082 ?attendance .
}
ORDER BY DESC(?attendance)
LIMIT 2

SELECT ?season ?numRaces WHERE {
  ?season wdt:P1350 ?numRaces .
  ?season wdt:P1346 wd:Q9673 .
}

SELECT ?club(COUNT(?win) AS ?premiershipCount) WHERE {
  ?club wdt:P1355 ?win .
}
GROUP BY ?club
HAVING(?club = wd:Q249679 || ?club = wd:Q2521385 || ?club = wd:Q251090 || ?club = wd:Q1084121 || ?club = wd:Q2738554)

SELECT ?player WHERE {
  ?player wdt:P641 wd:Q2070302
}

SELECT ?attendance WHERE {
  ?event wd:P1110 ?attendance
}
LIMIT 1

SELECT ?game WHERE {
  ?game ?p ?o
}

SELECT ?club(COUNT(?win) AS ?wins) WHERE {
  ?club wdt:P1355 ?win .
}
GROUP BY ?club
HAVING(?club = wd:Q249679 || ?club = wd:Q2521385)

SELECT ?event ?lapTime WHERE {
  ?event ?p ?lapTime
}

SELECT ?player ?birthYear WHERE {
  ?player wdt:P569 ?birthYear .
}

SELECT ?game ?duration WHERE {
  wd:Q334634 wdt:P710 ?game .
  ?game wdt:P1082 ?duration .
}

SELECT ?series ?venue WHERE {
  ?series wdt:P276 ?venue .
  FILTER(?series = wd:Q56692089 || ?series = wd:Q14870260 || ?series = wd:Q3511178)
}

SELECT ?season ?races WHERE {
  ?season wdt:P1346 wd:Q9673 .
  ?season ?races ?value .
  ?value a wd:Q108861375 .
}

SELECT ?game ?attendance WHERE {
  ?game wd:P1110 ?attendance .
  ?game ?p ?o .
}

SELECT ?season ?numRaces WHERE {
  ?season rdfs:label ?label .
  FILTER(CONTAINS(STR(?label) , "2000 Formula One World Championship"))
  ?season wdt:P1350 ?numRaces .
}
ORDER BY ?numRaces

SELECT ?series ?games WHERE {
  ?series wdt:P118 ?competition .
  ?series wdt:P1350 ?games .
}

SELECT ?team1 ?team2 ?series WHERE {
  ?team1 wdt:P118 wd:Q1363275 .
  ?team2 wdt:P118 wd:Q1363275 .
  ?team1 wdt:P1350 ?numGames .
  ?team2 wdt:P1350 ?numGames
}

SELECT(COUNT(?final) AS ?number_of_appearances) WHERE {
  wd:Q2521385 wdt:P1350 ?final .
  wd:Q249679 wdt:P1350 ?final .
}

SELECT ?year ?races WHERE {
  ?year wdt:P2522 wd:Q14293115 .
  ?year wdt:P1350 ?races .
}

SELECT ?time WHERE {
  wd:Q9673 wdtp:Q3_time ?time .
}

SELECT ?team(SUM(?points) AS ?totalPoints) WHERE {
  ?team wdt:P1923 wd:Q21189326 .
  ?team wdt:P1358 ?points .
}
GROUP BY ?team

SELECT ?player WHERE {
  ?player wdt:P118 ?tournament .
}

