  wd:Q4565436 wdt:P1923 ?team
}

SELECT ?driver ?team ?wins ?year WHERE {
  ?driver wdt:P1355 ?wins .
  ?driver wdt:P571 ?year .
  optional {
    ?team wdt:P1355 ?wins .
    ?team wdt:P571 ?year .
  }
  FILTER(?year > 2015 && ?driver = wd:Q9673 || ?team = wd:Q172721)
}

SELECT ?series ?wins WHERE {
  ?series wdt:P118 "National League Championship Series" ; wdt:P1355 ?wins .
}

SELECT ?series ?games WHERE {
  wd:Q213959 ?p ?games .
