  VALUES ?series {
    wd:Q56692089 wd:Q14870260 wd:Q3511178
  }
}

SELECT ?game(MAX(?duration) AS ?maxDuration) WHERE {
  ?game wdt:P2047 ?duration .
  ?game wdt:P1923 wd:Q334634 .
  ?game wdt:P1923 wd:Q650840 .
  ?game wdt:P118 wd:Q865526
}

SELECT ?game ?attendance WHERE {
  ?game wdt:P1923 wd:Q334634 .
  ?game wdt:P1923 wd:Q650840 .
  ?game wdt:P1110 ?attendance .
  ?game wdt:P1344 wd:Q1363275
}

SELECT ?games WHERE {
  wd:Q213959 wdt:P2522 ?championship .
  ?championship wdt:P1350 ?games
}

SELECT ?game ?duration WHERE {
  ?game wdt:P2047 ?duration .
  ?game ?p ?team1 .
  ?team1 wdt:P118 wd:Q858082 .
  ?team2 wdt:P118 wd:Q858082
}

SELECT ?team(COUNT(?final) AS ?appearances) WHERE {
  ?team wdt:P1350 ?final .
}
GROUP BY ?team
ORDER BY ?appearances
LIMIT 3

SELECT DISTINCT ?game WHERE {
  ?game wdt:P118 wd:Q1363275 .
  ?game wdt:P571 ?date .
  ?date wdt:P1401 ?yearValue
}

SELECT ?club(COUNT(?season) AS ?woodenSpoonCount) WHERE {
  ?club wdt:P5138 ?season .
  ?season wdt:P1352 "18" .
}
GROUP BY ?club
ORDER BY DESC(?woodenSpoonCount)

SELECT ?series1 ?series2 ?games1 ?games2(ABS(?games1 - ?games2) AS ?difference) WHERE {
  ?series1 wdt:P1350 ?games1 .
  ?series2 wdt:P1350 ?games2 .
  ?series1 rdfs:label "2008 National League Championship Series" @en .
  ?series2 rdfs:label "1977 National League Championship Series" @en
}

SELECT ?races WHERE {
  wd:Q69713 wdt:P1350 ?races
}

SELECT ?game ?attendance WHERE {
  ?game wdt:P1110 ?attendance .
  ?game wd:P118 wd:Q1172001 .
  ?game wd:P710 wd:Q334634 .
  ?game wd:P710 wd:Q650840
}

SELECT(COUNT(*) AS ?count) WHERE {
  ?event wdt:P31 wd:Q7965 .
  ?event wdt:P585 ?date .
  ?event wdt:P3764 wd:Q9673 .
  FILTER(YEAR(?date) >= 2016)
}
